36	  };
37	
38	  const menuItems = [
39	    { icon: CreditCard, label: t("profile.paymentsBilling"), path: "/profile/payments-billing" },
40	    { icon: Bell, label: t("profile.notifications"), path: "/profile/notifications" },
41	    { icon: Settings, label: t("profile.settings"), path: "/profile/settings" },
42	  ];
43	
44	  return (
45	    <Sheet open={isOpen} onOpenChange={onClose}>
46	      <SheetContent side="right" className="bg-black border-white/10 w-full sm:w-[320px]">
47	        <SheetHeader className="pb-6">
48	          <SheetTitle className="text-white font-vollkorn">{t("profile.menu")}</SheetTitle>
49	        </SheetHeader>
50	
51	        <div className="flex items-center gap-3 p-4 rounded-xl bg-white/5 mb-6">
52	          <Avatar className="h-12 w-12">
53	            <AvatarImage src={profile?.avatar_url} />
54	            <AvatarFallback className="bg-bronze text-white">
55	              {profile?.display_name?.charAt(0) || profile?.email?.charAt(0) || "U"}
56	            </AvatarFallback>
57	          </Avatar>
58	          <div className="flex-1 min-w-0">
59	            <p className="font-poppins text-sm font-semibold text-white truncate">
60	              {profile?.display_name || "User"}
61	            </p>
62	            <p className="text-xs text-white/50 truncate">{profile?.email}</p>
63	            <Badge
64	              variant="outline"
65	              className={
66	                userType === "creator"
67	                  ? "mt-1.5 text-[10px] font-semibold border-bronze text-bronze bg-bronze/15 px-2 py-0.5"
68	                  : "mt-1.5 text-[10px] font-semibold border-blue-400 text-blue-400 bg-blue-400/15 px-2 py-0.5"
69	              }
70	            >
71	              {userType === "creator" ? "Creator" : "Brand"}
72	            </Badge>
73	          </div>
74	        </div>
75	
76	        {/* Upgrade to Pro */}
77	        <Link
78	          to="/pricing"
79	          onClick={onClose}
80	          className="flex items-center gap-3 px-4 py-3 mb-2 rounded-lg bg-gradient-to-r from-bronze to-bronze-dark text-white hover:opacity-90 transition-all"
81	        >
82	          <Crown className="h-5 w-5" />
83	          <span className="font-poppins text-sm font-semibold">Upgrade to Pro</span>
84	        </Link>
85	
86	        <Separator className="bg-white/10 mb-4" />
87	
88	        <nav className="space-y-1">
89	          {menuItems.map((item) => {
90	            const Icon = item.icon;
91	            return (
92	              <Link
93	                key={item.path}
94	                to={item.path}
95	                onClick={onClose}
96	                className="flex items-center gap-3 px-4 py-3 rounded-lg text-white/80 hover:text-bronze hover:bg-white/5 transition-all"
97	              >
98	                <Icon className="h-5 w-5" />
99	                <span className="font-poppins text-sm font-medium">{item.label}</span>
100	              </Link>
101	            );
102	          })}
103	        </nav>
104	
105	        <Separator className="bg-white/10 my-4" />
106	
107	        <Button
108	          variant="ghost"
109	          onClick={handleSignOut}
110	          className="w-full justify-start gap-3 text-white/80 hover:text-red-400 hover:bg-white/5"
111	        >
112	          <LogOut className="h-5 w-5" />
113	          <span className="font-poppins text-sm font-medium">{t("profile.logout")}</span>
114	        </Button>
115	      </SheetContent>
116	    </Sheet>
117	  );
118	};
119	
120	export default ProfileDrawer;
