1	import { useState, useEffect } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	
4	export type SubscriptionPlan = "free" | "creative_pro" | "brand_workspace";
5	
6	export interface SubscriptionLimits {
7	  kiraActionsPerDay: number;
8	  invoicesPerMonth: number;
9	  contractsPerMonth: number;
10	  hasESignature: boolean;
11	  hasPremiumThemes: boolean;
12	  hasClientPortal: boolean;
13	  hasVerifiedBadge: boolean;
14	  hasFullAnalytics: boolean;
15	  hasUnlimitedInvoices: boolean;
16	  hasUnlimitedContracts: boolean;
17	}
18	
19	export interface SubscriptionState {
20	  plan: SubscriptionPlan;
21	  status: string;
22	  isLoading: boolean;
23	  isPro: boolean;
24	  isBrandWorkspace: boolean;
25	  isFree: boolean;
26	  limits: SubscriptionLimits;
27	  kiraActionsToday: number;
28	  kiraActionsLimit: number;
29	}
30	
31	const PLAN_LIMITS: Record<SubscriptionPlan, SubscriptionLimits> = {
32	  free: {
33	    kiraActionsPerDay: 10,
34	    invoicesPerMonth: 5,
35	    contractsPerMonth: 5,
36	    hasESignature: false,
37	    hasPremiumThemes: false,
38	    hasClientPortal: false,
39	    hasVerifiedBadge: false,
40	    hasFullAnalytics: false,
41	    hasUnlimitedInvoices: false,
42	    hasUnlimitedContracts: false,
43	  },
44	  creative_pro: {
45	    kiraActionsPerDay: 40,
46	    invoicesPerMonth: Infinity,
47	    contractsPerMonth: Infinity,
48	    hasESignature: true,
49	    hasPremiumThemes: true,
50	    hasClientPortal: true,
51	    hasVerifiedBadge: true,
52	    hasFullAnalytics: true,
53	    hasUnlimitedInvoices: true,
54	    hasUnlimitedContracts: true,
55	  },
56	  brand_workspace: {
57	    kiraActionsPerDay: 40,
58	    invoicesPerMonth: Infinity,
59	    contractsPerMonth: Infinity,
60	    hasESignature: true,
61	    hasPremiumThemes: true,
62	    hasClientPortal: true,
63	    hasVerifiedBadge: true,
64	    hasFullAnalytics: true,
65	    hasUnlimitedInvoices: true,
66	    hasUnlimitedContracts: true,
67	  },
68	};
69	
70	// A plan only grants Pro/Workspace features when the subscription is active or trialing.
71	const ACTIVE_STATUSES = new Set(["active", "trialing"]);
72	
73	export const useSubscription = (): SubscriptionState => {
74	  const [plan, setPlan] = useState<SubscriptionPlan>("free");
75	  const [status, setStatus] = useState("inactive");
76	  const [isLoading, setIsLoading] = useState(true);
77	  const [kiraActionsToday, setKiraActionsToday] = useState(0);
78	  const [kiraActionsLimit, setKiraActionsLimit] = useState(10);
79	
80	  const applyProfile = (profile: Record<string, unknown>) => {
81	    setPlan((profile.subscription_plan as SubscriptionPlan) || "free");
82	    setStatus((profile.subscription_status as string) || "inactive");
83	    setKiraActionsToday((profile.kira_actions_used as number) || 0);
84	    setKiraActionsLimit((profile.kira_actions_limit as number) || 10);
85	  };
86	
87	  useEffect(() => {
88	    let channel: ReturnType<typeof supabase.channel> | null = null;
89	
90	    const setup = async () => {
91	      const { data: { user } } = await supabase.auth.getUser();
92	      if (!user) {
93	        setIsLoading(false);
94	        return;
95	      }
96	
97	      const { data: profile } = await supabase
98	        .from("profiles")
99	        .select("subscription_plan, subscription_status, kira_actions_used, kira_actions_limit")
100	        .eq("id", user.id)
101	        .single();
102	
103	      if (profile) applyProfile(profile as Record<string, unknown>);
104	      setIsLoading(false);
105	
106	      // Real-time listener: fires the moment the Paystack webhook updates the profile row.
107	      channel = supabase
108	        .channel(`subscription:${user.id}`)
109	        .on(
110	          "postgres_changes",
111	          {
112	            event: "UPDATE",
113	            schema: "public",
114	            table: "profiles",
115	            filter: `id=eq.${user.id}`,
116	          },
117	          (payload) => {
118	            applyProfile(payload.new as Record<string, unknown>);
119	          }
120	        )
121	        .subscribe();
122	    };
123	
124	    setup();
125	
126	    return () => {
127	      if (channel) supabase.removeChannel(channel);
128	    };
129	  }, []);
130	
131	  const currentPlan = plan || "free";
132	  const limits = PLAN_LIMITS[currentPlan];
133	  const isActiveStatus = ACTIVE_STATUSES.has(status);
134	
135	  return {
136	    plan: currentPlan,
137	    status,
138	    isLoading,
139	    isPro: currentPlan === "creative_pro" && isActiveStatus,
140	    isBrandWorkspace: currentPlan === "brand_workspace" && isActiveStatus,
141	    isFree: currentPlan === "free" || !isActiveStatus,
142	    limits,
143	    kiraActionsToday,
144	    kiraActionsLimit,
145	  };
146	};
