1	import { useState, useEffect } from "react";
2	import { Link, useNavigate, useSearchParams } from "react-router-dom";
3	import { Button } from "@/components/ui/button";
4	import { Card } from "@/components/ui/card";
5	import { Input } from "@/components/ui/input";
6	import { Label } from "@/components/ui/label";
7	import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
8	import { supabase } from "@/integrations/supabase/client";
9	import { useToast } from "@/hooks/use-toast";
10	import { Eye, EyeOff, Loader2, Palette, Crown, Check } from "lucide-react";
11	import { Checkbox } from "@/components/ui/checkbox";
12	import { cn } from "@/lib/utils";
13	
14	const hasOAuthCallback = () => {
15	  const params = new URLSearchParams(window.location.search);
16	  return params.has("code") || params.has("token_hash") || window.location.hash.includes("access_token");
17	};
18	
19	const Auth = () => {
20	  const navigate = useNavigate();
21	  const [searchParams] = useSearchParams();
22	  const { toast } = useToast();
23	  const [isSignup, setIsSignup] = useState(searchParams.get("mode") === "signup");
24	  const [email, setEmail] = useState("");
25	  const [password, setPassword] = useState("");
26	  const [showPassword, setShowPassword] = useState(false);
27	  const [showForgotPassword, setShowForgotPassword] = useState(false);
28	  const [resetEmail, setResetEmail] = useState("");
29	  const [isResetting, setIsResetting] = useState(false);
30	  const [isGoogleLoading, setIsGoogleLoading] = useState(false);
31	  // const [isAppleLoading, setIsAppleLoading] = useState(false);
32	  const [isLoading, setIsLoading] = useState(false);
33	  const [userType, setUserType] = useState<"creator" | "brand">("creator");
34	  const [termsAccepted, setTermsAccepted] = useState(false);
35	  const [passwordErrors, setPasswordErrors] = useState<string[]>([]);
36	  const [emailConfirmPending, setEmailConfirmPending] = useState(false);
37	  const [pendingEmail, setPendingEmail] = useState("");
38	  const [isResendingConfirm, setIsResendingConfirm] = useState(false);
39	  // True when we landed here from a Google OAuth redirect — hide the form while Supabase exchanges the code.
40	  const [isProcessingOAuth, setIsProcessingOAuth] = useState(hasOAuthCallback);
41	
42	  const validatePassword = (pwd: string): string[] => {
43	    const errors: string[] = [];
44	    if (pwd.length < 8) errors.push("At least 8 characters");
45	    if (!/[A-Z]/.test(pwd)) errors.push("One uppercase letter");
46	    if (!/[a-z]/.test(pwd)) errors.push("One lowercase letter");
47	    if (!/[0-9]/.test(pwd)) errors.push("One number");
48	    if (!/[^A-Za-z0-9]/.test(pwd)) errors.push("One special character");
49	    return errors;
50	  };
51	
52	  const handlePasswordChange = (value: string) => {
53	    setPassword(value);
54	    if (isSignup) setPasswordErrors(validatePassword(value));
55	  };
56	
57	  useEffect(() => {
58	    // Check if user is already logged in
59	    supabase.auth.getSession().then(async ({ data: { session } }) => {
60	      if (session) {
61	        const { data: aalData } = await supabase.auth.mfa.getAuthenticatorAssuranceLevel();
62	        if (aalData?.nextLevel === "aal2" && aalData?.nextLevel !== aalData?.currentLevel) {
63	          navigate("/mfa-verify", { replace: true });
64	        } else {
65	          navigate("/kira", { replace: true });
66	        }
67	      }
68	    });
69	
70	    // Listen for auth state changes (for OAuth redirects)
71	    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
72	      if (event === 'SIGNED_IN' && session) {
73	        const { data: aalData } = await supabase.auth.mfa.getAuthenticatorAssuranceLevel();
74	        if (aalData?.nextLevel === "aal2" && aalData?.nextLevel !== aalData?.currentLevel) {
75	          navigate("/mfa-verify", { replace: true });
76	        } else {
77	          navigate("/kira", { replace: true });
78	        }
79	      } else if (event !== 'INITIAL_SESSION' && isProcessingOAuth) {
80	        // Exchange failed — fall back to showing the login form.
81	        setIsProcessingOAuth(false);
82	      }
83	    });
84	
85	    return () => subscription.unsubscribe();
86	  }, [navigate]);
87	
88	  const handleResendConfirmation = async () => {
89	    setIsResendingConfirm(true);
90	    const { error } = await supabase.auth.resend({
91	      type: "signup",
92	      email: pendingEmail,
93	      options: { emailRedirectTo: `${window.location.origin}/auth` },
94	    });
95	    setIsResendingConfirm(false);
96	    if (error) {
97	      toast({ title: "Couldn't resend", description: error.message, variant: "destructive" });
98	    } else {
99	      toast({ title: "Email resent", description: "A new confirmation link has been sent to your inbox." });
100	    }
101	  };
102	
103	  const handleGoogleSignIn = async () => {
104	    if (isSignup && !termsAccepted) {
105	      toast({
106	        title: "Please agree first",
107	        description: "Tick the Terms of Use and Privacy Policy checkbox before continuing.",
108	        variant: "destructive",
109	      });
110	      return;
111	    }
112	
113	    setIsGoogleLoading(true);
114	    try {
115	      const { error } = await supabase.auth.signInWithOAuth({
116	        provider: 'google',
117	        options: {
118	          redirectTo: `${window.location.origin}/auth`,
119	          queryParams: {
120	            access_type: 'offline',
121	            prompt: 'select_account',
122	          },
123	        },
124	      });
125	
126	      if (error) {
127	        toast({
128	          title: "Google sign-in failed",
129	          description: error.message,
130	          variant: "destructive"
131	        });
132	        setIsGoogleLoading(false);
133	      }
134	    } catch (err) {
135	      console.error("Google auth error:", err);
136	      toast({
137	        title: "Connection error",
138	        description: "Unable to connect to Google. Please check your internet and try again.",
139	        variant: "destructive"
140	      });
141	      setIsGoogleLoading(false);
142	    }
143	  };
144	
145	  // const handleAppleSignIn = async () => {
146	  //   setIsAppleLoading(true);
147	  //   try {
148	  //     const { error } = await supabase.auth.signInWithOAuth({
149	  //       provider: 'apple',
150	  //       options: {
151	  //         redirectTo: `${window.location.origin}/auth`,
152	  //         queryParams: {
153	  //           prompt: 'login',
154	  //         },
155	  //       },
156	  //     });
157	
158	  //     if (error) {
159	  //       toast({ 
160	  //         title: "Apple sign-in failed 😅", 
161	  //         description: error.message, 
162	  //         variant: "destructive" 
163	  //       });
164	  //       setIsAppleLoading(false);
165	  //     }
166	  //   } catch (err) {
167	  //     console.error("Apple auth error:", err);
168	  //     toast({ 
169	  //       title: "Connection hiccup! 📡", 
170	  //       description: "Unable to connect to Apple. Please try again.", 
171	  //       variant: "destructive" 
172	  //     });
173	  //     setIsAppleLoading(false);
174	  //   }
175	  // };
176	
177	  const handleAuth = async (e: React.FormEvent) => {
178	    e.preventDefault();
179	    setIsLoading(true);
180	
181	    try {
182	      if (isSignup) {
183	        const errors = validatePassword(password);
184	        if (errors.length > 0) {
185	          setPasswordErrors(errors);
186	          setIsLoading(false);
187	          return;
188	        }
189	        const { data: signUpData, error } = await supabase.auth.signUp({
190	          email,
191	          password,
192	          options: {
193	            emailRedirectTo: `${window.location.origin}/auth`,
194	            data: {
195	              user_type: userType,
196	            },
197	          },
198	        });
199	
200	        if (error) {
201	          const msg = error.message.toLowerCase();
202	          if (msg.includes("already registered") || msg.includes("already exists")) {
203	            toast({
204	              title: "Account already exists",
205	              description: "An account with this email already exists. Try logging in instead.",
206	              variant: "destructive",
207	            });
208	            setIsSignup(false);
209	          } else if (msg.includes("rate limit") || msg.includes("email rate")) {
210	            toast({
211	              title: "Too many attempts",
212	              description: "Please wait a few minutes before trying again.",
213	              variant: "destructive",
214	            });
215	          } else {
216	            toast({
217	              title: "Sign up failed",
218	              description: "Something went wrong on our end. Please try again in a moment.",
219	              variant: "destructive",
220	            });
221	            console.error("Signup error:", error.message);
222	          }
223	        } else if (signUpData.session) {
224	          // User is immediately signed in (email confirmation disabled)
225	          const { data: aalData } = await supabase.auth.mfa.getAuthenticatorAssuranceLevel();
226	          if (aalData?.nextLevel === "aal2" && aalData?.nextLevel !== aalData?.currentLevel) {
227	            navigate("/mfa-verify", { replace: true });
228	          } else {
229	            navigate("/kira", { replace: true });
230	          }
231	        } else {
232	          // Email confirmation required — show dedicated screen
233	          setPendingEmail(email);
234	          setEmailConfirmPending(true);
235	        }
236	      } else {
237	        const { data, error } = await supabase.auth.signInWithPassword({
238	          email,
239	          password,
240	        });
241	
242	        if (error) {
243	          const msg = error.message.toLowerCase();
244	          if (msg.includes("invalid login") || msg.includes("invalid credentials") || msg.includes("wrong password")) {
245	            toast({ title: "Incorrect email or password", description: "Please check your details and try again.", variant: "destructive" });
246	          } else if (msg.includes("email not confirmed")) {
247	            toast({ title: "Email not confirmed", description: "Please check your inbox and click the confirmation link we sent you.", variant: "destructive" });
248	          } else {
249	            toast({ title: "Sign in failed", description: error.message, variant: "destructive" });
250	          }
251	        } else if (data.user) {
252	          toast({ title: "Welcome back!", description: "Good to see you." });
253	          // navigation is handled by the onAuthStateChange SIGNED_IN listener above
254	        }
255	      }
256	    } catch (err) {
257	      console.error("Auth error:", err);
258	      toast({ 
259	        title: "Connection hiccup! 📡", 
260	        description: "Unable to connect to the server. Please check your internet and try again.", 
261	        variant: "destructive" 
262	      });
263	    } finally {
264	      setIsLoading(false);
265	    }
266	  };
267	
268	  const handleForgotPassword = async (e: React.FormEvent) => {
269	    e.preventDefault();
270	    setIsResetting(true);
271	
272	    const { error } = await supabase.auth.resetPasswordForEmail(resetEmail, {
273	      redirectTo: `${window.location.origin}/reset-password`,
274	    });
275	
276	    setIsResetting(false);
277	
278	    if (error) {
279	      toast({
280	        title: "Oops! 😅",
281	        description: error.message,
282	        variant: "destructive",
283	      });
284	    } else {
285	      toast({
286	        title: "Check your inbox! 📧",
287	        description: "We sent you a link to reset your password.",
288	      });
289	      setShowForgotPassword(false);
290	      setResetEmail("");
291	    }
292	  };
293	
294	  if (isProcessingOAuth) {
295	    return (
296	      <div className="min-h-screen bg-gradient-to-br from-background via-bronze/5 to-background flex items-center justify-center p-4">
297	        <div className="flex flex-col items-center gap-4 text-center">
298	          <Loader2 className="w-10 h-10 animate-spin text-bronze" />
299	          <p className="font-poppins text-muted-foreground">Signing you in…</p>
300	        </div>
301	      </div>
302	    );
303	  }
304	
305	  if (emailConfirmPending) {
306	    return (
307	      <div className="min-h-screen bg-gradient-to-br from-background via-bronze/5 to-background flex items-center justify-center p-4 md:p-6">
308	        <Card className="w-full max-w-md p-6 md:p-8 mx-4 animate-fade-in text-center">
309	          <div className="mb-6">
310	            <img src="/crevia-logo.png" alt="Crevia Logo" className="w-10 h-10 mx-auto mb-4" />
311	            <h1 className="font-vollkorn text-2xl font-bold mb-2">Confirm your email</h1>
312	            <p className="text-muted-foreground text-sm leading-relaxed">
313	              An email was sent to<br />
314	              <span className="font-semibold text-foreground">{pendingEmail}</span>
315	            </p>
316	          </div>
317	          <p className="text-sm text-muted-foreground mb-6">
318	            Kindly click the link in the email to confirm your account and get access to Kira. Check your spam folder if you don't see it.
319	          </p>
320	          <Button
321	            className="w-full h-12 bg-bronze hover:bg-bronze-dark font-semibold"
322	            onClick={handleResendConfirmation}
323	            disabled={isResendingConfirm}
324	          >
325	            {isResendingConfirm ? "Sending..." : "Resend confirmation link"}
326	          </Button>
327	        </Card>
328	      </div>
329	    );
330	  }
331	
332	  return (
333	    <div className="min-h-screen bg-gradient-to-br from-background via-bronze/5 to-background flex items-center justify-center p-4 md:p-6">
