1	import { useState, useEffect } from "react";
2	import { useLocation } from "react-router-dom";
3	import { useTheme } from "next-themes";
4	import { supabase } from "@/integrations/supabase/client";
5	import MainSidebar from "./MainSidebar";
6	import MobileBottomNav from "./MobileBottomNav";
7	import TopBar from "./TopBar";
8	import ProfileDrawer from "./ProfileDrawer";
9	
10	interface AppLayoutProps {
11	  children: React.ReactNode;
12	}
13	
14	const AppLayout = ({ children }: AppLayoutProps) => {
15	  const location = useLocation();
16	  const { setTheme } = useTheme();
17	  const [userType, setUserType] = useState<"creator" | "brand" | null>(null);
18	  const [profile, setProfile] = useState<any>(null);
19	  const [loading, setLoading] = useState(true);
20	  const [profileDrawerOpen, setProfileDrawerOpen] = useState(false);
21	
22	  useEffect(() => {
23	    const appTheme = localStorage.getItem("app-theme");
24	    if (appTheme) {
25	      setTheme(appTheme);
26	    }
27	    loadProfile();
28	
29	    // Re-load profile when the session is established after a PKCE OAuth exchange
30	    // (getSession() above may return null if the code is still being exchanged).
31	    const { data: { subscription } } = supabase.auth.onAuthStateChange((event) => {
32	      if (event === "SIGNED_IN") {
33	        loadProfile();
34	      }
35	    });
36	
37	    return () => subscription.unsubscribe();
38	  }, []);
39	
40	  const loadProfile = async () => {
41	    const { data: { session } } = await supabase.auth.getSession();
42	
43	    if (session) {
44	      const { data: profileData } = await supabase
45	        .from("profiles")
46	        .select("*")
47	        .eq("id", session.user.id)
48	        .single();
49	
50	      setProfile(profileData);
51	      setUserType(profileData?.user_type || null);
52	    } else {
53	      setUserType("creator");
54	      setProfile({ display_name: "Guest", email: "" });
55	    }
56	    setLoading(false);
57	  };
58	
59	  if (loading) {
60	    return (
61	      <div className="min-h-screen bg-black flex items-center justify-center">
62	        <div className="text-white/60 font-poppins">Loading...</div>
63	      </div>
64	    );
65	  }
66	
67	  if (!userType || !profile) {
68	    return null;
69	  }
70	
71	  const isCrevidAI = location.pathname === "/crevia-ai";
72	
73	  return (
74	    <div className="min-h-screen bg-background flex flex-col">
75	      <TopBar
76	        profile={profile}
77	        onProfileClick={() => setProfileDrawerOpen(true)}
78	        hideRightElements={isCrevidAI}
79	      />
80	
81	      <div className="flex flex-1 overflow-hidden">
82	        <MainSidebar
83	          userType={userType}
84	          profile={profile}
85	          onProfileClick={() => setProfileDrawerOpen(true)}
86	        />
87	
88	        <main className="flex-1 overflow-auto pb-16 md:pb-0 md:ml-[100px]">
89	          {children}
90	        </main>
91	      </div>
92	
93	      <MobileBottomNav />
94	
95	      <ProfileDrawer
96	        isOpen={profileDrawerOpen}
97	        onClose={() => setProfileDrawerOpen(false)}
98	        profile={profile}
99	        userType={userType}
100	      />
101	    </div>
102	  );
103	};
104	
105	export default AppLayout;
